  # rubocop:enable Layout/LineLength

  # @param name [Symbol, String] key in ICON_PATHS
  # @param size [Integer] px width/height
  # @param klass [String] extra CSS classes on the <svg>
  def icon(name, size: 20, klass: "icon")
    paths = ICON_PATHS[name.to_sym]
    return "".html_safe if paths.nil?

    attrs = %(class="#{klass}" width="#{size}" height="#{size}" viewBox="0 0 24 24" ) +
            %(fill="none" stroke="currentColor" stroke-width="2" ) +
            %(stroke-linecap="round" stroke-linejoin="round" aria-hidden="true")
    # Static, developer-authored SVG paths — no user input — so marking the
    # assembled markup html_safe is intentional.
    "<svg #{attrs}>#{paths}</svg>".html_safe # rubocop:disable Rails/OutputSafety
  end
